#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v;
    n->left = n->right = NULL;
    return n;
}

void inorder(Node* r) {
    if (!r) return;
    inorder(r->left);
    printf("%d ", r->val);
    inorder(r->right);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node** nodes = (Node**)malloc((N+1)*sizeof(Node*));
        bool* isChild = (bool*)calloc(N+1, sizeof(bool));
        for (int i=1;i<=N;i++) nodes[i]=newNode(i);
        for (int i=0;i<N-1;i++) {
            int p,c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (dir=='L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
            isChild[c]=true;
        }
        int root=1; for (int i=1;i<=N;i++) if (!isChild[i]) {root=i; break;}
        inorder(nodes[root]);
        printf("\n");
        free(isChild);
        free(nodes);
    }
    return 0;
}

