import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val; Node left, right;
        Node(int v){val=v;}
    }
    static void inorder(Node r, StringBuilder sb){
        if(r==null) return;
        inorder(r.left, sb);
        sb.append(r.val).append(' ');
        inorder(r.right, sb);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            Node[] nodes = new Node[N+1];
            boolean[] isChild = new boolean[N+1];
            for(int i=1;i<=N;i++) nodes[i]=new Node(i);
            for(int i=0;i<N-1;i++){
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if(dir=='L') nodes[p].left = nodes[c];
                else nodes[p].right = nodes[c];
                isChild[c]=true;
            }
            int root=1; for(int i=1;i<=N;i++) if(!isChild[i]){root=i; break;}
            StringBuilder sb = new StringBuilder();
            inorder(nodes[root], sb);
            out.append(sb.toString().trim()).append('\n');
        }
        System.out.print(out.toString());
    }
}

