const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = parseInt(data[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(data[idx++]);
  const nodes = Array.from({ length: N }, (_, i) => ({ val: i + 1, left: null, right: null }));
  const isChild = new Array(N).fill(false);
  for (let i = 0; i < N - 1; i++) {
    const p = parseInt(data[idx++]) - 1;
    const c = parseInt(data[idx++]) - 1;
    const dir = data[idx++];
    if (dir === 'L') nodes[p].left = nodes[c];
    else nodes[p].right = nodes[c];
    isChild[c] = true;
  }
  let root = 0;
  for (let i = 0; i < N; i++) if (!isChild[i]) { root = i; break; }
  const res = [];
  function inorder(node) {
    if (!node) return;
    inorder(node.left);
    res.push(node.val);
    inorder(node.right);
  }
  inorder(nodes[root]);
  outputs.push(res.join(' '));
}
